import java.util.*;class P4{public static void main(String[] a){Scanner s=new Scanner(System.in);int n=s.nextInt();int max=10;int[] d=new int[max];int idx=0;while(n!=0){if(idx==max){max+=10;int[] t=new int[max];for(int i=0;i<idx;i++)t[i]=d[i];d=t;}d[idx++]=n%10;n/=10;}int l=0,sl=0;for(int i=0;i<idx;i++){if(d[i]>l){sl=l;l=d[i];}else if(d[i]>sl&&d[i]!=l)sl=d[i];}System.out.println(l+" "+sl);}}